  color: var(--cor-texto-secundario);
  font-weight: 600;
  margin: 0;
}

.store-title {
  font-weight: bold;
  font-size: 14px;
  color: var(--cor-texto-principal);
  margin: 0;
  letter-spacing: 1.5px;
}

