  .projects {
    min-height: auto;
    padding: 30px 20px;
  }

  .cards-wrapper {
    align-items: center;
    gap: 10px;
    justify-content: center;
    flex-wrap: nowrap;
  }

  .game-card {
    width: 200px;
    max-width: 200px;
    border-radius: 16px;
  }

  .section-game {
    margin-bottom: 20px;
  }

  .section-subtitle {
    font-size: 12px;
    max-width: 400px;
  }

  .game-image-container {
    border-radius: 0 0 16px 16px;
  }

  .game-image {
    max-width: 200px;
    border-radius: 0 0 16px 16px;
  }

  .badge {
    padding: 4px 8px;
    font-size: 8px;
  }

  .hover-info {
    padding: 10px;
  }

  .card-body {
    padding: 10px;
  }

  .game-title {
    font-size: 14px;
  }

  .tool-tag {
    padding: 4px 10px;
    border-radius: 10px;
    font-size: 11px;
  }

  .store-btn {
    padding: 4px;
    border-radius: 10px;
    gap: 2px;
  }

  .store-icon {
    width: 25px;
    height: 25px;
  }

  .store-subtitle {
    font-size: 7px;
  }

  .store-title {
    font-size: 10px;
  }
}
</style>